import{_ as i,o as t,c as n,ag as r}from"./chunks/framework.DXGyWiRo.js";const l="/images/lekt5402.jpg",a="/images/lekt5401.jpg",m=JSON.parse('{"title":"Lektion 54","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/lektion54.md","filePath":"lektionen/lektion54.md"}'),s={name:"lektionen/lektion54.md"};function u(d,e,o,p,h,b){return t(),n("div",null,[...e[0]||(e[0]=[r('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="lektion-54" tabindex="-1">Lektion 54 <a class="header-anchor" href="#lektion-54" aria-label="Permalink to &quot;Lektion 54&quot;">​</a></h1><h2 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h2><ul><li>54.1. Vorbemerkung</li><li>54.2. Wortbildung: कृत्-Suffix -u an Desiderativstämme</li><li>54.3. Metrik II: die epische त्रिष्टुभ् und die जगती</li><li>54.4. Übung zur Metrik</li><li>54.5. Bildungstypen des Aorist (लुङ्)</li><li>54.6. Wurzelaorist <ul><li>54.6.1. Der Aorist der 3.sg.Passiv</li></ul></li><li>54.7. Übung</li></ul><h2 id="_54-1-vorbemerkung" tabindex="-1">54.1. Vorbemerkung <a class="header-anchor" href="#_54-1-vorbemerkung" aria-label="Permalink to &quot;54.1. Vorbemerkung&quot;">​</a></h2><p>Mit Lektion 54 beginnt im Universitätsunterricht das 2. Semester. Ab jetzt läuft der Kurs nur noch neben dem Hauptthema dieses Semesters: der Lektüre der ganzen Bhagavadgītā. Lernziel ist eine solche Geläufigkeit im Lesen eines mittelschweren Textes, dass im letzten Drittel des Semesters große Teile der Bhagavadgītā aus dem Stegreif übersetzt werden können. Zu Beginn wurden im Universitätsunterricht noch Wortlisten ausgeteilt, später mussten die Studierenden selbst entsprechende Wörterbücher (Monier-Williams, Apte, PW) benutzen.</p><p>Der Kurs zur Bhagavadgītā wird vorläufig noch nicht online zur Verfügung gestellt.</p><p>Die Lektionen des Sanskritkurses behandeln Themen der Sanskritgrammatik, die bisher noch nicht behandelt wurden.</p><h2 id="_54-2-wortbildung-कृत्-suffix-u-an-desiderativstamme" tabindex="-1">54.2. Wortbildung: कृत्-Suffix -u an Desiderativstämme <a class="header-anchor" href="#_54-2-wortbildung-कृत्-suffix-u-an-desiderativstamme" aria-label="Permalink to &quot;54.2. Wortbildung: कृत्-Suffix -u an Desiderativstämme&quot;">​</a></h2><p>An Desiderativstämme (इच्छाप्रकृति) (&quot;etwas zu tun wünschen&quot; ; &quot;im Begriffe sein, etwas zu tun&quot;) tritt zur Bildung von Nomina agentis das Suffix -u.</p><p>(Bildung der Desiderativstämme folgt später)</p><p>Beispiel:</p><blockquote><p>युयुत्सु (yu-yudh + s + u) &quot;kampfebegierig, im Begriffe, zu kämpfen&quot;</p></blockquote><p><img src="'+l+'" alt=""><br> Abb.: अयुयुत्सुरर्जुनः<br> भगवद्गीतोपदेशः<br> Tirupati = తిరుపతి<br> [Bildquelle: Raji Srinivas / Wikipedia. GNU FDLicense]</p><h2 id="_54-3-metrik-ii-die-epische-त्रिष्टुभ्-und-die-जगती" tabindex="-1">54.3. Metrik II: die epische त्रिष्टुभ् und die जगती <a class="header-anchor" href="#_54-3-metrik-ii-die-epische-त्रिष्टुभ्-und-die-जगती" aria-label="Permalink to &quot;54.3. Metrik II: die epische त्रिष्टुभ् und die जगती&quot;">​</a></h2><p>Die त्रिष्टुभ् (&quot;Drei-Jauchzer&quot;) erscheint in den Epen inmitten der üblichen श्लोक-Partien gerade an Stellen, wo Stimmung oder Handlung einen besonderen Aufschwung oder Abschluss erfahren.</p><p>Die त्रिष्टुभ्-Strophe besteht aus vier elfsilbigen पाद, die sich im Bau nicht voneinander unterscheiden.</p><p>Die त्रिष्टुभ् hat zwei Grundschemata, je nachdem, ob die Zäsur (Wortende, Kompositionsfuge oder vor bestimmten Suffixen wie -tara, -tama u.ä.) nach der 4. oder 5. Silbe des पाद steht.</p><p>Schema I:</p><blockquote><p>̽ ˉ ̽ ˉ / ̽ ˘ˉˉ˘ˉˉ</p></blockquote><p>Schema II:</p><blockquote><p>̽ ˉ ̽ ˉ ̽  / ̽ ˘ˉ˘ˉˉ</p></blockquote><p>Die Quantität der vier letzten Silben ist also in beiden Schemata gleich.</p><p>जगती-Grundform: wie bei त्रिष्टुभ्, aber 12-silbig. Die letzten 5 Silben jedes Pada heben folgende Quantitäten:</p><blockquote><p>ˉ˘ˉ˘ˉ</p></blockquote><p>Daneben gibt es die sog. typisch überzählige त्रिष्टुभ् mit fünfsilbigem Anfangsglied, die weitergeht wie eine त्रिष्टुभ् mit viersilbigem Anfangsglied:</p><blockquote><p>ˉ ̽ ˉ ̽  / ̽ ˘ˉˉ˘ˉˉ</p></blockquote><p>In späterer Zeit werden die Formen der त्रिष्टुभ् festgelegt nach einem strengen Schema der Längen und Kürzen, die Zäsur spielt keine Rolle mehr. Die wichtigsten späteren Formen sind:</p><p>a) इन्द्रवज्रा</p><blockquote><p>ˉˉ˘ˉ,ˉ˘˘ˉ˘ˉˉ</p></blockquote><p>b) उपेन्द्रवज्रा</p><blockquote><p>˘ˉ˘ˉ,ˉ˘˘ˉ˘ˉˉ</p></blockquote><p>c) उपजाति</p><blockquote><p>पाद in इन्द्रवज्रा und पाद in उपेन्द्रवज्रा sind in eine Strophe gemischt.</p></blockquote><p>Merkverse:</p><p>स्यादिन्द्रवज्रा यदि तौ जगौ गः ।</p><blockquote><p>&quot;Es ist eine Indravājrā, wenn die Silben in allen Pādas ta ta ja ga ga sind.</p></blockquote><p>उपेन्द्रवज्रा प्रथमे लघौ सा ।</p><blockquote><p>&quot;Eine Upendravajrā ist wie eine Indravajrā, die am Anfang eine leichte Silben hat&quot;</p></blockquote><p>अनन्तरोदीरितलक्ष्मभाजौ<br> पदौ यदीयावुपजातयस्ताः ।<br> इत्थं किलान्यास्वपिमिश्रितासु<br> वदन्ति जातिष्विदमिदमेवनाम ॥</p><blockquote><p>&quot;Wenn zwei Pādas, die die Merkmale von Indravajrā bzw. Upendravajrā haben, an einem Vers beteiligt sind, dann sind es Upajātis. Auch wenn andere Metren in einem Vers gemischt sind, nennt man es Upajāti.&quot;</p></blockquote><h2 id="_54-4-ubung-zur-metrik" tabindex="-1">54.4. Übung zur Metrik <a class="header-anchor" href="#_54-4-ubung-zur-metrik" aria-label="Permalink to &quot;54.4. Übung zur Metrik&quot;">​</a></h2><p>Bestimmen Sie in Bhagavadgītā II Triṣṭubhs und Jagatīs.</p><p>Beispiel einer Rezitation: <a href="http://www.vaisnava.cz/gita/mp3/Bhagavad-gita02.mp3" target="_blank" rel="noreferrer">http://www.vaisnava.cz/gita/mp3/Bhagavad-gita02.mp3</a>. -- Zugriff am 2009-01-28</p><h2 id="_54-5-bildungstypen-des-aorist-लुङ्" tabindex="-1">54.5. Bildungstypen des Aorist (लुङ्) <a class="header-anchor" href="#_54-5-bildungstypen-des-aorist-लुङ्" aria-label="Permalink to &quot;54.5. Bildungstypen des Aorist (लुङ्)&quot;">​</a></h2><p>Gemeinsam ist allen Bildungstypen des Aorist (लुङ्) das Augment a-, das nach den gleichen Regeln wie im Imperfekt (लङ्) vorgesetzt wird.</p><p>Vom Aorist sind im Sanskrit nur Indikativ und Prekativ gebvräuchlich.</p><p>Es gibt folgende Bildungstypen des Aorist (लुङ्):</p><ol><li>Nichtsibilantische (asigmatische) Aoriste: <ul><li>54.1. Wurzelaorist: Augment + Wurzel + Sekundärendung</li><li>54.2. Themavokalischer Aorist: Augment + Wurzel + a + Sekundärendung</li><li>54.3. Reduplizierter Aorist: Augment + reduplizierte Wurzel + a + Sekundärendung</li></ul></li><li>Sibilantische (sigmatische Aoriste: s oder eine Silbe, die s (ṣ) enthält tritt vor die Personalendung <ul><li>54.4. -s-Aorist: Augment + Wurzel + s + Sekundärendung</li><li>54.5. -iṣ-Aorist: Augment + Wurzel + i + ṣ + Sekundärendung</li><li>54.6. -siṣ-Aorist: Augment + Wurzel + siṣ + Sekundärendung</li><li>54.7. -sa-Aorist: Augment + Wurzel + s + a + Sekundärendung</li></ul></li></ol><p>Verteilung der Wurzeln auf die einzelnen Bildungstypen siehe bei den einzelnen Typen</p><h2 id="_54-6-wurzelaorist" tabindex="-1">54.6. Wurzelaorist <a class="header-anchor" href="#_54-6-wurzelaorist" aria-label="Permalink to &quot;54.6. Wurzelaorist&quot;">​</a></h2><p>Bildung:</p><p>Augment + Wurzel + Sekundärendung</p><p>Endung der 3.pl.P ist -ur. Ātmanepada ist nicht gebräuchlich.</p><p>Beispiel:</p><p>पा 1P &quot;trinken&quot;</p><blockquote><table tabindex="0"><thead><tr><th></th><th>एकवचनम्</th><th>बहुवचनम्</th></tr></thead><tbody><tr><td>1. तृतीयः</td><td>अपाम्</td><td></td></tr><tr><td>a-pā + am</td><td>अपाम</td><td></td></tr><tr><td>2. मध्यमः</td><td>अपास्</td><td>अपात</td></tr><tr><td>3. प्रथमः</td><td>अपात्</td><td>अपुर्</td></tr><tr><td>a-p-ur (Tiefstufe!)</td><td></td><td></td></tr></tbody></table></blockquote><p>Nur von 12 Wurzeln wird der Wurzelaorist gebildet:</p><ol><li>गा 3 &quot;gehen&quot;</li><li>घ्रा 1P &quot;riechen&quot;</li><li>छो 6 &quot;schneiden&quot; (अच्छात्)</li><li>दा 3U &quot;geben&quot;</li><li>दो  1, 4 &quot;schneiden&quot;</li><li>धा 3U &quot;setzen&quot;</li><li>धे 1 &quot;saugen&quot; (अधात्)</li><li>पा 1P &quot;trinken&quot;</li><li>शो 4P &quot;schärfen&quot;</li><li>सो &quot;beendigen&quot;</li><li>स्था 1P &quot;stehen&quot;</li><li>भू 1P &quot;sein</li></ol><p>Zu भू 1P wird der Wurzelaorist so gebildet:</p><blockquote><table tabindex="0"><thead><tr><th></th><th>एकवचनम्</th><th>बहुवचनम्</th></tr></thead><tbody><tr><td>1. तृतीयः</td><td>अभूवम्</td><td>अभूम</td></tr><tr><td>2. मध्यमः</td><td>अभू्स्</td><td>अभूत</td></tr><tr><td>3. प्रथमः</td><td>अभूत्</td><td>अभूवन् (!!!)</td></tr></tbody></table></blockquote><h3 id="_54-6-1-der-aorist-der-3-sg-passiv" tabindex="-1">54.6.1. Der Aorist der 3.sg.Passiv <a class="header-anchor" href="#_54-6-1-der-aorist-der-3-sg-passiv" aria-label="Permalink to &quot;54.6.1. Der Aorist der 3.sg.Passiv&quot;">​</a></h3><p>Eine Spezialform des Wurzelaorist ist der Aorist der 3.sg.Passiv. Dieser kann von allen Wurzeln gebildet werden.</p><p>Bildung:</p><p>Augment + Wurzel + i</p><p>Die Wurzel hat folgende Gestalt:</p><p>Hochstufe:</p><ul><li>Wurzeln mit kurzem Vokal (außer a) vor einfachem Konsonanten sowie जन् und die meisten Wurzeln auf -am<br> Beispiele:<br> भिद् 7U: अभेदि &quot;er wurde gespalten&quot;<br> तुद् 6U: अतोदि &quot;er wurde gestoßen&quot;</li></ul><p>Dehnstufe:</p><ul><li><p>Wurzeln mit auslautendem Vokal<br> Beispiele:<br> नी 1U: अनायि &quot;er wurde geführt&quot;<br> स्तु 2U: अस्तावि &quot;sie wurde gelobt&quot;<br> कृ 8U: अकारि &quot;es wurde gemacht&quot;</p></li><li><p>Wurzeln mit a vor einfachem Konsonanten (außer जन् und Wurzeln auf -am)<br> Beispiel:<br> वद् 1P: अवादि &quot;es wurde gesagt&quot;<br> aber:<br> जन् 4Ā: अजनि &quot;sie wurde geboren&quot;</p></li><li><p>einige Wurzeln auf -am<br> Beispiel:<br> गम् अगामि</p></li></ul><p>Einschub von y vor Endung:</p><ul><li>Wurzeln auf -ā, -e, -ai, -o schieben zwischen das -ā der Wurzel und die Endung ein y ein:<br> Beispiel:<br> दा 3U: अदायि &quot;es wurde gegeben&quot;</li></ul><p>Nasalinfix:</p><ul><li>einige Wurzeln haben ein Nasalinfix:<br> Beispiel:<br> लभ् 1Ā: अलम्भि neben अलाभि : &quot;es wurde empfangen&quot;</li></ul><p>(Die übrigen Formen des Passiv werden im Aorist durch Ātmanepada-formen wiedergegeben).</p><h2 id="_54-7-ubung" tabindex="-1">54.7. Übung <a class="header-anchor" href="#_54-7-ubung" aria-label="Permalink to &quot;54.7. Übung&quot;">​</a></h2><p>Übersetzen Sie schriftlich folgende Formen und bilden Sie die entsprechenden Aoristformen:</p><ol><li>यन्ति</li><li>पिबामि</li><li>ददौ</li><li>बभूव</li><li>दधति</li><li>ऐम</li><li>पपिथ</li><li>तिष्ठति</li><li>इयेथ</li><li>पप</li><li>एष्यथ</li><li>तस्थुः</li><li>अधत्त</li><li>अददाः</li><li>अभवन्</li><li>ददिम</li><li>भिद्यते</li><li>उद्यते</li><li>स्तूयते</li><li>कृष्यते</li><li>जायते (Pass.)</li><li>गीयते</li><li>गम्यते</li></ol><p><img src="'+a+'" alt=""><br> Abb.: त्रिचक्रेणेश्वरः स्तूयते<br> Tamil Nadu<br> [Bildquelle: driek. -- <a href="http://www.flickr.com/photos/driek/2411004380/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/driek/2411004380/</a>. -- Zugriff am 2009-01-28. -- <a href="http://creativecommons.org/licenses/by-nc-sa/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung, shre alike)]</p>',79)])])}const c=i(s,[["render",u]]);export{m as __pageData,c as default};
